@schema 
class HarpOutputExpanderRetriedDelivery(dj.Imported):
        definition = """ # Raw per-chunk RetriedDelivery from HarpOutputExpander (v-unknown)
    -> HarpOutputExpander
    -> acquisition.Chunk
    ---
    sample_count: int      # number of data points acquired from this stream for a given chunk
    timestamps: longblob   # (datetime) timestamps of RetriedDelivery data
    retried_delivery: longblob
    """

        @property
        def key_source(self):
            """Only the combination of Chunk and HarpOutputExpander with overlapping time.

            + Chunk(s) started after HarpOutputExpander install time & ended before HarpOutputExpander remove time
            + Chunk(s) started after HarpOutputExpander install time for HarpOutputExpander and not yet removed
            """
            return (
                acquisition.Chunk * HarpOutputExpander.join(HarpOutputExpander.RemovalTime, left=True)
                & "chunk_start >= harp_output_expander_install_time"
                & 'chunk_start < IFNULL(harp_output_expander_removal_time,"2200-01-01")'
            )

